class SamePlaceModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.judge = dspy.Predict(dspy.Signature(
            'input_name: str, input_address: str, match_name: str, match_address: str, distance: float -> is_same: bool',
            "Decide whether two business listings refer to the same physical place. "
            "Consider name similarity, address similarity, and distance in meters."
        ))

    def forward(self, **inputs):
        import re

        def normalize_name(s):
            s = (s or "").lower()
            # remove punctuation
            s = re.sub(r"[^\w\s&]", " ", s)
            s = re.sub(r"\s+", " ", s).strip()
            # remove common business suffixes/tokens
            stopwords = {
                "the", "a", "an", "and", "of", "co", "company", "corp", "corporation",
                "inc", "incorporated", "llc", "ltd", "limited", "llp", "lp", "plc",
                "restaurant", "cafe", "shop", "store",
            }
            tokens = [t for t in s.split() if t not in stopwords]
            # drop trailing pure-digit tokens (e.g., "2", "#3") which often denote branch numbers
            while tokens and tokens[-1].isdigit():
                tokens.pop()
            return " ".join(tokens).strip()

        def normalize_address(s):
            s = (s or "").lower()
            s = re.sub(r"[^\w\s]", " ", s)
            s = re.sub(r"\s+", " ", s).strip()
            # normalize common street suffix abbreviations
            repl = {
                "street": "st", "avenue": "ave", "av": "ave", "boulevard": "blvd",
                "road": "rd", "drive": "dr", "lane": "ln", "court": "ct",
                "place": "pl", "square": "sq", "highway": "hwy", "parkway": "pkwy",
                "terrace": "ter", "circle": "cir",
                "north": "n", "south": "s", "east": "e", "west": "w",
                "northeast": "ne", "northwest": "nw", "southeast": "se", "southwest": "sw",
            }
            tokens = [repl.get(t, t) for t in s.split()]
            return " ".join(tokens).strip()

        def extract_street_number(addr):
            m = re.match(r"^\s*(\d+)", addr or "")
            return m.group(1) if m else None

        def token_set_ratio(a, b):
            ta, tb = set(a.split()), set(b.split())
            if not ta or not tb:
                return 0.0
            inter = ta & tb
            return len(inter) / max(len(ta), len(tb))

        def char_ratio(a, b):
            # simple ratio via difflib
            import difflib
            return difflib.SequenceMatcher(None, a, b).ratio()

        try:
            dist = float(inputs.get("distance", 0.0) or 0.0)
        except Exception:
            dist = 0.0

        n1 = normalize_name(inputs.get("input_name", ""))
        n2 = normalize_name(inputs.get("match_name", ""))
        a1 = normalize_address(inputs.get("input_address", ""))
        a2 = normalize_address(inputs.get("match_address", ""))

        num1 = extract_street_number(a1)
        num2 = extract_street_number(a2)

        name_tok = token_set_ratio(n1, n2) if (n1 and n2) else 0.0
        name_char = char_ratio(n1, n2) if (n1 and n2) else 0.0
        name_sim = max(name_tok, name_char)

        addr_tok = token_set_ratio(a1, a2) if (a1 and a2) else 0.0
        addr_char = char_ratio(a1, a2) if (a1 and a2) else 0.0
        addr_sim = max(addr_tok, addr_char)

        # Deterministic rules

        # Rule 1: Exact same normalized address (including street number) AND close distance
        # and reasonable name overlap -> same place.
        if a1 and a2 and a1 == a2 and dist <= 50:
            return dspy.Prediction(is_same=True)

        # Rule 2: Same street number, high address similarity, high name similarity, close.
        if num1 and num2 and num1 == num2 and addr_sim >= 0.85 and name_sim >= 0.6 and dist <= 100:
            return dspy.Prediction(is_same=True)

        # Rule 3: Very far apart -> not same.
        if dist >= 200:
            return dspy.Prediction(is_same=False)

        # Rule 4: Different street numbers and not extremely close -> not same.
        if num1 and num2 and num1 != num2 and dist >= 50:
            return dspy.Prediction(is_same=False)

        # Rule 5: Very different addresses (low similarity) and not co-located -> not same.
        if addr_sim < 0.4 and dist >= 50:
            return dspy.Prediction(is_same=False)

        # Rule 6: Very different names AND different street numbers -> not same.
        if name_sim < 0.3 and (not num1 or not num2 or num1 != num2):
            return dspy.Prediction(is_same=False)

        # Rule 7: Identical normalized names AND close distance -> same.
        if n1 and n2 and n1 == n2 and dist <= 100:
            return dspy.Prediction(is_same=True)

        # Ambiguous -> defer to LLM.
        result = self.judge(
            input_name=inputs.get("input_name", ""),
            input_address=inputs.get("input_address", ""),
            match_name=inputs.get("match_name", ""),
            match_address=inputs.get("match_address", ""),
            distance=dist,
        )
        return dspy.Prediction(is_same=bool(result.is_same))
